mapper.select:
select article.*, user.name as userName, user.avatar as avatar, (select count(*) from `likes` where likes.article_id = article.id) as likeCount, (select count(*) from `comments` where comments.article_id = article.id) as commentCount, (select l.id from `likes` l where l.article_id = article.id and l.user_id = #{loginUserId} limit 1) as likedId from `article` left join user on article.user_id = user.id
and article.title like concat('%', #{title}, '%') and article.user_id = #{userId} and article.status = #{status}
order by article.id desc

mapper.update:
update `article`
img = #{img}, title = #{title}, description = #{description}, content = #{content}, time = #{time}, user_id = #{userId}, status = #{status}, reason = #{reason},
where id = #{id}
